-- ============================================================
-- RAKAL (ركال) — Database Schema & Seed Data
-- Charset: utf8mb4 | Engine: InnoDB
-- ============================================================

CREATE DATABASE IF NOT EXISTS rakal_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE rakal_db;

-- ============================================================
-- TABLE: services
-- ============================================================
CREATE TABLE IF NOT EXISTS services (
  id                INT AUTO_INCREMENT PRIMARY KEY,
  title             VARCHAR(255) NOT NULL,
  slug              VARCHAR(255) NOT NULL UNIQUE,
  icon              VARCHAR(100),
  description       TEXT,
  overview_content  LONGTEXT,
  full_content      LONGTEXT,
  color_scheme      ENUM('cyan','gold'),
  subservices       JSON,
  stats             JSON,
  target_businesses JSON,
  benefits          JSON,
  tech_stack        JSON,
  workflow          JSON,
  faq               JSON,
  featured_image    VARCHAR(500),
  grid_col_span     TINYINT DEFAULT 1,
  sort_order        INT DEFAULT 0,
  is_active         TINYINT(1) DEFAULT 1,
  created_at        TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at        TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ============================================================
-- TABLE: blogs
-- ============================================================
CREATE TABLE IF NOT EXISTS blogs (
  id              INT AUTO_INCREMENT PRIMARY KEY,
  title           VARCHAR(255) NOT NULL,
  slug            VARCHAR(255) NOT NULL UNIQUE,
  excerpt         TEXT,
  content         LONGTEXT,
  author          VARCHAR(255) DEFAULT 'فريق رقال التقني',
  category        VARCHAR(100),
  category_color  ENUM('cyan','gold'),
  featured_image  VARCHAR(500),
  read_time       INT,
  is_featured     TINYINT(1) DEFAULT 0,
  is_active       TINYINT(1) DEFAULT 1,
  published_at    DATETIME,
  created_at      TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at      TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ============================================================
-- TABLE: admins
-- ============================================================
CREATE TABLE IF NOT EXISTS admins (
  id                   INT AUTO_INCREMENT PRIMARY KEY,
  username             VARCHAR(100) NOT NULL UNIQUE,
  password_hash        VARCHAR(255),
  must_change_password TINYINT(1) DEFAULT 1,
  created_at           TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ============================================================
-- SEED: services
-- ============================================================

-- Service 1: تطوير المواقع والمنصات (full data from service-detail.html)
INSERT INTO services (
  title, slug, icon, description, overview_content, full_content,
  color_scheme, subservices, stats, target_businesses, benefits,
  tech_stack, workflow, faq, featured_image, grid_col_span, sort_order, is_active
) VALUES (
  'تطوير المواقع والمنصات',
  'tatawwur-almawaqi-walmanssat',
  'web',
  'بناء منصات إلكترونية متوافقة مع معايير الحكومة الرقمية، تجمع بين الأداء العالي والتصميم العصري مع دعم كامل للغة العربية وتجربة المستخدم المحلي.',
  '<p>نقدم خدمة تطوير مواقع ومنصات رقمية متكاملة تشمل كل مراحل المشروع من التحليل والتخطيط إلى التصميم والتطوير والإطلاق والمتابعة. نعتمد على أحدث التقنيات العالمية مع مراعاة المتطلبات المحلية والمعايير الحكومية السعودية للخدمات الرقمية.</p>
<p>سواء كنت تحتاج إلى بوابة حكومية إلكترونية، موقع مؤسسي احترافي، منصة تعليمية تفاعلية، أو نظام متكامل لإدارة المحتوى، فريقنا المتخصص يمتلك الخبرة التقنية والمعرفة القطاعية لتقديم حل يلبي احتياجاتك بدقة.</p>
<p>نحرص على أن تكون كل منصة نطورها سريعة الأداء، آمنة، سهلة الاستخدام، ومتوافقة مع معايير الوصول العالمية لضمان وصول أكبر شريحة من المستخدمين إليها بأفضل تجربة ممكنة.</p>',
  NULL,
  'cyan',
  '["مواقع الشركات", "البوابات الحكومية", "لوحات التحكم", "المنصات التعليمية"]',
  '[{"label": "موقع ومنصة تم تسليمها", "value": "+١٥٠"}, {"label": "توافق مع المعايير", "value": "٪١٠٠"}, {"label": "دعم فني متواصل", "value": "24/7"}, {"label": "تقنية معتمدة", "value": "+٣٠"}]',
  '[{"title": "الجهات الحكومية", "description": "بوابات إلكترونية متوافقة مع المعايير الحكومية", "icon": "account_balance"}, {"title": "الشركات الكبرى", "description": "مواقع مؤسسية تعكس الهوية الرقمية وتعزز الحضور التجاري", "icon": "domain"}, {"title": "المؤسسات التعليمية", "description": "منصات تعليمية تفاعلية تدعم التعلم الرقمي", "icon": "school"}, {"title": "القطاع الصحي", "description": "بوابات مرضى وأنظمة حجز مواعيد ذكية", "icon": "local_hospital"}]',
  '[{"title": "أداء فائق السرعة", "description": "مواقع محسّنة وفق أعلى معايير الأداء تحقق درجات متميزة في Core Web Vitals وتضمن تجربة تصفح سلسة.", "icon": "speed"}, {"title": "تصميم متجاوب", "description": "تجربة مستخدم مثالية ومتسقة على كل الأجهزة من الهاتف المحمول إلى الشاشات الكبيرة بلا استثناء.", "icon": "devices"}, {"title": "أمان متقدم", "description": "حماية شاملة من الثغرات الأمنية مع تشفير البيانات وتطبيق أحدث بروتوكولات الأمان الرقمي.", "icon": "lock"}, {"title": "صديق لمحركات البحث", "description": "بنية تقنية محسّنة للـ SEO من الأساس تضمن ظهور موقعك في صدارة نتائج البحث وزيادة الزيارات العضوية.", "icon": "search"}, {"title": "دعم ثنائي اللغة", "description": "تجربة عربية وإنجليزية متكاملة بسلاسة تامة مع دعم كامل لاتجاه النص RTL/LTR وخطوط احترافية لكلتا اللغتين.", "icon": "translate"}, {"title": "سهولة الوصول", "description": "متوافق مع معايير WCAG للوصول الرقمي لضمان وصول جميع المستخدمين بما فيهم ذوو الاحتياجات الخاصة.", "icon": "accessibility"}]',
  '["React", "Next.js", "Vue.js", "Laravel", "Node.js", "Python", "WordPress", "Tailwind CSS", "PostgreSQL", "MongoDB", "AWS", "Docker"]',
  '[{"title": "تحليل المتطلبات", "description": "نبدأ بفهم أهدافك التجارية وجمهورك المستهدف وملامح المشروع بالكامل. نجري دراسة شاملة للمنافسين والسوق لوضع أساس متين للمشروع."}, {"title": "التصميم والنمذجة", "description": "نصمم واجهات المستخدم بدقة عالية ونبني نماذج تفاعلية للاعتماد قبل البدء في التطوير، مما يوفر الوقت ويضمن توافق الرؤية."}, {"title": "التطوير والبرمجة", "description": "نبني الموقع أو المنصة باستخدام أحدث التقنيات مع تطبيق أفضل الممارسات البرمجية وضمان جودة الكود ومراجعته بشكل مستمر."}, {"title": "الإطلاق والمتابعة", "description": "نشر الموقع على البنية التحتية المناسبة مع مراقبة الأداء والأمان بشكل مستمر وتقديم تقارير دورية عن حالة المنصة."}]',
  '[{"question": "كم يستغرق تطوير موقع إلكتروني؟", "answer": "يعتمد على حجم المشروع ومتطلباته التقنية. الموقع التعريفي البسيط يستغرق عادةً ٤-٦ أسابيع، بينما المنصات المتكاملة تحتاج إلى ٨-١٢ أسبوعاً. نقدم جدولاً زمنياً تفصيلياً في بداية كل مشروع."}, {"question": "هل يمكنني إدارة محتوى الموقع بنفسي؟", "answer": "نعم بالتأكيد. نوفر لوحة تحكم سهلة الاستخدام مصممة خصيصاً لتمكينك من إدارة المحتوى دون الحاجة إلى أي خبرة تقنية. نقدم أيضاً جلسات تدريبية وأدلة استخدام مفصلة."}, {"question": "هل يشمل السعر الاستضافة؟", "answer": "نقدم باقات استضافة اختيارية على خوادم سحابية عالية الأداء، كما يمكننا العمل مع مزود الاستضافة المفضل لديك. نرشدك لاختيار الحل الأنسب وفق حجم مشروعك وميزانيتك."}, {"question": "هل توفرون خدمات الصيانة بعد الإطلاق؟", "answer": "نعم، نقدم باقات صيانة ودعم فني شهرية تشمل تحديثات الأمان، مراقبة الأداء، إصلاح الأخطاء، وتحديثات المحتوى. فريقنا متاح على مدار الساعة للتعامل مع أي طارئ."}]',
  'uploads/services/web-platforms.jpg',
  2,
  1,
  1
);

-- Service 2: تطبيقات الجوال
INSERT INTO services (
  title, slug, icon, description, overview_content, full_content,
  color_scheme, subservices, stats, target_businesses, benefits,
  tech_stack, workflow, faq, featured_image, grid_col_span, sort_order, is_active
) VALUES (
  'تطبيقات الجوال',
  'tatbiqat-aljawwal',
  'smartphone',
  'تطوير تطبيقات iOS و Android بأحدث التقنيات، بأداء سلس وتجربة مستخدم عربية أصيلة تناسب كل فئات الجمهور.',
  '<p>نتخصص في تطوير تطبيقات جوال احترافية تعمل بسلاسة على منصتي iOS و Android، مع التركيز على تقديم تجربة مستخدم استثنائية تراعي خصوصية المستخدم السعودي والعربي. نستخدم أحدث أطر العمل مثل Flutter و React Native لضمان أداء عالٍ وتكلفة تطوير مُحسَّنة.</p>
<p>سواء كنت تحتاج إلى تطبيق توصيل، تطبيق مؤسسي داخلي، منصة تجارة إلكترونية متنقلة، أو تطبيق خدمات حكومية، فإن فريقنا يمتلك الخبرة في بناء تطبيقات قابلة للتوسع تخدم ملايين المستخدمين مع الحفاظ على استقرار الأداء وأمان البيانات.</p>
<p>نحرص على تطبيق أفضل ممارسات تصميم واجهات الجوال مع دعم كامل للغة العربية واتجاه RTL، وتكامل سلس مع بوابات الدفع المحلية مثل مدى و Apple Pay و STC Pay، بالإضافة إلى خدمات الإشعارات والموقع الجغرافي.</p>',
  NULL,
  'gold',
  '["تطبيقات أصلية", "تطبيقات متعددة المنصات", "تطبيقات المؤسسات", "تطبيقات التوصيل"]',
  '[{"label": "تطبيق تم إطلاقه", "value": "+٨٠"}, {"label": "مستخدم نشط", "value": "+٢م"}, {"label": "تقييم متوسط على المتاجر", "value": "٤.٨"}, {"label": "نسبة الاحتفاظ بالمستخدمين", "value": "٪٨٥"}]',
  '[{"title": "قطاع التجزئة والتوصيل", "description": "تطبيقات توصيل وتجارة متنقلة بتجربة شراء سلسة وتتبع مباشر للطلبات", "icon": "local_shipping"}, {"title": "القطاع المالي والبنكي", "description": "تطبيقات بنكية ومحافظ رقمية بأعلى معايير الأمان والتشفير", "icon": "account_balance_wallet"}, {"title": "القطاع الصحي", "description": "تطبيقات حجز مواعيد واستشارات طبية عن بُعد ومتابعة صحية ذكية", "icon": "health_and_safety"}, {"title": "الجهات الحكومية", "description": "تطبيقات خدمات حكومية تسهّل وصول المواطنين إلى الخدمات الرقمية", "icon": "assured_workload"}]',
  '[{"title": "أداء أصلي فائق", "description": "تطبيقات بأداء يضاهي التطبيقات الأصلية بفضل استخدام أحدث أطر العمل وتقنيات التحسين، مع زمن استجابة لا يتجاوز ميلي ثوانٍ.", "icon": "bolt"}, {"title": "تجربة مستخدم عربية أصيلة", "description": "تصميم واجهات تراعي ثقافة المستخدم العربي والسعودي مع دعم كامل لاتجاه RTL وخطوط عربية احترافية وتجربة تنقل بديهية.", "icon": "touch_app"}, {"title": "تكامل بوابات الدفع المحلية", "description": "ربط سلس مع مدى و Apple Pay و STC Pay وغيرها من بوابات الدفع المعتمدة في المملكة لتسهيل عمليات الشراء.", "icon": "payments"}, {"title": "إشعارات ذكية ومخصصة", "description": "نظام إشعارات متقدم يدعم الاستهداف الذكي والتخصيص بناءً على سلوك المستخدم وتفضيلاته لزيادة التفاعل والاحتفاظ.", "icon": "notifications_active"}, {"title": "عمل بدون اتصال", "description": "دعم وضع عدم الاتصال مع مزامنة تلقائية للبيانات عند عودة الاتصال، لضمان استمرارية الاستخدام في جميع الظروف.", "icon": "wifi_off"}, {"title": "أمان وحماية متقدمة", "description": "تشفير شامل للبيانات مع دعم المصادقة البيومترية ببصمة الإصبع والوجه وتطبيق أحدث بروتوكولات حماية التطبيقات.", "icon": "fingerprint"}]',
  '["Flutter", "React Native", "Swift", "Kotlin", "Firebase", "Node.js", "GraphQL", "PostgreSQL", "Redis", "AWS Amplify", "CI/CD"]',
  '[{"title": "دراسة الفكرة والتخطيط", "description": "نحلل فكرة التطبيق ونحدد الجمهور المستهدف ونرسم خارطة طريق واضحة تشمل الميزات الأساسية والتقنيات المناسبة والجدول الزمني."}, {"title": "التصميم والنماذج التفاعلية", "description": "نصمم واجهات المستخدم بدقة عالية ونبني نماذج تفاعلية قابلة للاختبار على الأجهزة الفعلية للتأكد من سلاسة التجربة قبل البرمجة."}, {"title": "التطوير والاختبار", "description": "نبرمج التطبيق بأحدث التقنيات مع اختبارات مستمرة على أجهزة متعددة، ونطبق منهجية التكامل المستمر لضمان جودة الكود واستقراره."}, {"title": "الإطلاق والنمو", "description": "ننشر التطبيق على App Store و Google Play مع تحسين صفحة التطبيق ASO، ونتابع التحليلات ونقدم تحديثات دورية بناءً على ملاحظات المستخدمين."}]',
  '[{"question": "هل تطورون تطبيقات لنظام واحد أم لكلا النظامين؟", "answer": "نطور لكلا النظامين iOS و Android. باستخدام تقنيات مثل Flutter و React Native نبني تطبيقاً واحداً يعمل على المنصتين بأداء ممتاز، مما يوفر التكلفة ويسرّع الإطلاق. كما نطور تطبيقات أصلية بلغة Swift أو Kotlin عند الحاجة لأداء متخصص."}, {"question": "كم تكلفة تطوير تطبيق جوال؟", "answer": "تعتمد التكلفة على حجم المشروع وتعقيده. التطبيقات البسيطة تبدأ من ٥٠ ألف ريال، بينما التطبيقات المتقدمة قد تصل إلى ٣٠٠ ألف ريال أو أكثر. نقدم عرض سعر تفصيلي بعد دراسة متطلباتك بدقة."}, {"question": "هل توفرون خدمة نشر التطبيق على المتاجر؟", "answer": "نعم، نتولى عملية النشر الكاملة على App Store و Google Play بما فيها إعداد حسابات المطورين وتحسين صفحة التطبيق والوصف والصور التوضيحية لضمان أفضل ظهور وتحميلات."}, {"question": "هل يمكن ربط التطبيق بنظام موجود لدينا؟", "answer": "بالتأكيد. نتخصص في تكامل التطبيقات مع الأنظمة القائمة سواء كانت أنظمة ERP أو CRM أو قواعد بيانات أو واجهات برمجة خارجية. نضمن تدفق البيانات بسلاسة وأمان بين جميع الأنظمة."}]',
  'uploads/services/mobile-apps.jpg',
  1,
  2,
  1
);

-- Service 3: أنظمة ERP و CRM
INSERT INTO services (
  title, slug, icon, description, overview_content, full_content,
  color_scheme, subservices, stats, target_businesses, benefits,
  tech_stack, workflow, faq, featured_image, grid_col_span, sort_order, is_active
) VALUES (
  'أنظمة ERP و CRM',
  'anzimat-erp-wa-crm',
  'settings_suggest',
  'أنظمة إدارة موارد متكاملة متوافقة مع ZATCA، تغطي جميع عمليات المؤسسة من المالية إلى الموارد البشرية.',
  '<p>نقدم حلول ERP و CRM شاملة مصممة خصيصاً للسوق السعودي، تتوافق بالكامل مع متطلبات هيئة الزكاة والضريبة والجمارك ZATCA للفوترة الإلكترونية. أنظمتنا تربط جميع أقسام المؤسسة في منظومة رقمية واحدة تسهّل اتخاذ القرارات وتزيد الكفاءة التشغيلية.</p>
<p>من إدارة المحاسبة والمالية إلى سلاسل الإمداد والمخزون والموارد البشرية والمشتريات، نوفر نظاماً متكاملاً يُغني عن الأنظمة المتفرقة ويقضي على جزر البيانات المعزولة. كما نخصص وحدات CRM متقدمة لإدارة علاقات العملاء وتتبع فرص المبيعات وتحسين خدمة ما بعد البيع.</p>
<p>نعتمد على منصات عالمية مثل Odoo و SAP Business One مع تخصيص كامل يناسب احتياجات كل عميل، بالإضافة إلى بناء أنظمة مخصصة بالكامل للمؤسسات ذات المتطلبات الفريدة. جميع حلولنا تدعم اللغة العربية بالكامل وتتكامل مع الأنظمة الحكومية السعودية.</p>',
  NULL,
  'cyan',
  '["الفوترة الإلكترونية", "إدارة الموظفين", "سلاسل الإمداد", "التقارير المالية"]',
  '[{"label": "نظام تم تنفيذه", "value": "+٦٠"}, {"label": "توافق مع ZATCA", "value": "٪١٠٠"}, {"label": "نسبة رضا العملاء", "value": "٪٩٧"}, {"label": "ساعات عمل موفّرة شهرياً", "value": "+٥٠٠٠"}]',
  '[{"title": "الشركات المتوسطة والكبرى", "description": "أنظمة ERP متكاملة تربط جميع الأقسام وتوحّد العمليات التشغيلية في منصة واحدة", "icon": "corporate_fare"}, {"title": "قطاع التجزئة والتوزيع", "description": "إدارة متقدمة للمخزون وسلاسل الإمداد ونقاط البيع مع تتبع لحظي للمنتجات", "icon": "store"}, {"title": "شركات المقاولات", "description": "إدارة المشاريع والعقود والمستخلصات مع نظام محاسبي متوافق مع طبيعة قطاع البناء", "icon": "engineering"}, {"title": "القطاع الصناعي", "description": "تخطيط الإنتاج وإدارة خطوط التصنيع ومراقبة الجودة مع تتبع المواد الخام", "icon": "factory"}]',
  '[{"title": "توافق كامل مع ZATCA", "description": "نظام فوترة إلكترونية متوافق بالكامل مع المرحلتين الأولى والثانية من متطلبات هيئة الزكاة والضريبة والجمارك، مع تحديثات تلقائية عند صدور تعديلات.", "icon": "verified"}, {"title": "لوحات تحكم ذكية", "description": "تقارير ولوحات بيانات تفاعلية تعرض مؤشرات الأداء الرئيسية في الوقت الفعلي لتمكين الإدارة من اتخاذ قرارات مبنية على بيانات دقيقة.", "icon": "dashboard"}, {"title": "أتمتة العمليات", "description": "أتمتة سير العمل والموافقات والإشعارات لتقليل المهام اليدوية المتكررة وتسريع دورة العمل وتقليل الأخطاء البشرية بشكل كبير.", "icon": "auto_mode"}, {"title": "تكامل شامل", "description": "ربط سلس مع البنوك المحلية وبوابات الدفع والأنظمة الحكومية ومنصات التجارة الإلكترونية لضمان تدفق البيانات بدون تدخل يدوي.", "icon": "hub"}, {"title": "أمان المستوى المؤسسي", "description": "تشفير شامل للبيانات مع صلاحيات وصول دقيقة لكل مستخدم وسجل تدقيق كامل لجميع العمليات لضمان الامتثال والحوكمة.", "icon": "admin_panel_settings"}, {"title": "دعم عربي متكامل", "description": "واجهة عربية بالكامل مع تقويم هجري وميلادي ودعم للعملات المحلية وصيغ التاريخ والعناوين السعودية بما يتناسب مع بيئة العمل المحلية.", "icon": "language"}]',
  '["Odoo", "SAP Business One", "Laravel", "Python", "PostgreSQL", "Redis", "Docker", "Kubernetes", "Power BI", "Jasper Reports", "RabbitMQ", "Elasticsearch"]',
  '[{"title": "تحليل العمليات القائمة", "description": "نجري دراسة شاملة لعمليات المؤسسة الحالية ونحدد نقاط الضعف وفرص التحسين، ونرسم خريطة تدفق العمليات المستهدفة بعد التطبيق."}, {"title": "التصميم والتخصيص", "description": "نصمم بنية النظام ونخصص الوحدات وفق متطلبات كل قسم، مع تجهيز خطة ترحيل البيانات من الأنظمة القديمة وإعداد سيناريوهات الاختبار."}, {"title": "التنفيذ والتدريب", "description": "ننفذ النظام على مراحل بدءاً بالأقسام الأكثر أولوية، مع تدريب مكثف للموظفين وتوفير أدلة استخدام تفصيلية بالعربية لكل وحدة."}, {"title": "الدعم والتحسين المستمر", "description": "نقدم دعم فني متواصل بعد الإطلاق مع مراقبة أداء النظام وتحسينه دورياً، ونُطبّق التحديثات التنظيمية فور صدورها من الجهات الرسمية."}]',
  '[{"question": "هل النظام متوافق مع الفوترة الإلكترونية ZATCA؟", "answer": "نعم، جميع أنظمتنا متوافقة بالكامل مع متطلبات المرحلة الأولى (الإصدار) والمرحلة الثانية (الربط والتكامل) من منظومة الفوترة الإلكترونية. نحدّث النظام تلقائياً عند صدور أي تعديلات من الهيئة."}, {"question": "كم يستغرق تطبيق نظام ERP؟", "answer": "يعتمد على حجم المؤسسة وعدد الوحدات المطلوبة. التطبيق الأساسي يستغرق ٨-١٢ أسبوعاً، بينما الأنظمة الشاملة للمؤسسات الكبرى قد تحتاج ٤-٦ أشهر. نعتمد منهجية التنفيذ المرحلي لضمان أقل تأثير على سير العمل."}, {"question": "هل يمكن ترحيل بياناتنا من النظام القديم؟", "answer": "بالتأكيد. لدينا خبرة واسعة في ترحيل البيانات من أنظمة متنوعة مثل Excel وQuickBooks وأنظمة ERP أخرى. نضمن سلامة البيانات ودقتها مع مراجعة شاملة بعد الترحيل للتحقق من التكامل."}, {"question": "هل يدعم النظام الفروع المتعددة؟", "answer": "نعم، أنظمتنا تدعم إدارة فروع متعددة بصلاحيات منفصلة مع إمكانية التقارير الموحدة على مستوى المنشأة. يمكن لكل فرع العمل بشكل مستقل مع مزامنة فورية للبيانات على المستوى المركزي."}]',
  'uploads/services/erp-crm-systems.jpg',
  1,
  3,
  1
);

-- Service 4: المتاجر الإلكترونية
INSERT INTO services (
  title, slug, icon, description, overview_content, full_content,
  color_scheme, subservices, stats, target_businesses, benefits,
  tech_stack, workflow, faq, featured_image, grid_col_span, sort_order, is_active
) VALUES (
  'المتاجر الإلكترونية',
  'almatajir-aleliktruniyya',
  'shopping_cart',
  'حلول تجارة إلكترونية متكاملة مع بوابات دفع محلية وتجربة تسوق عربية سلسة تحقق أعلى معدلات التحويل.',
  '<p>نبني متاجر إلكترونية متكاملة تجمع بين التصميم الجذاب والأداء التقني العالي، مع التركيز على تحسين معدلات التحويل وتجربة التسوق للعميل السعودي. من واجهة المتجر إلى نظام إدارة المنتجات والطلبات، نوفر حلاً شاملاً يُمكّنك من إدارة تجارتك الإلكترونية بكفاءة.</p>
<p>نتكامل مع جميع بوابات الدفع المعتمدة في المملكة بما فيها مدى و SADAD و Tamara للتقسيط و Tabby، بالإضافة إلى شركات الشحن المحلية مثل أرامكس و SMSA و سمسا وغيرها. كما نضمن توافق المتجر الكامل مع نظام التجارة الإلكترونية السعودي ومتطلبات ضريبة القيمة المضافة.</p>
<p>سواء كنت تبدأ مشروعك التجاري الأول أو تنقل متجرك الحالي إلى منصة أكثر تطوراً، نقدم حلولاً مرنة تنمو مع نمو أعمالك من مئات المنتجات إلى ملايين، مع أدوات تسويق مدمجة وتحليلات متقدمة لتتبع الأداء وتحسين المبيعات.</p>',
  NULL,
  'gold',
  '["تصميم المتجر", "إدارة المنتجات", "بوابات الدفع", "التكامل مع الشحن"]',
  '[{"label": "متجر إلكتروني تم بناؤه", "value": "+١٢٠"}, {"label": "معاملة ناجحة تمت معالجتها", "value": "+٥م"}, {"label": "متوسط زيادة المبيعات", "value": "٪٣٥٠"}, {"label": "بوابة دفع وشحن متكاملة", "value": "+١٥"}]',
  '[{"title": "تجار التجزئة", "description": "متاجر إلكترونية متكاملة لعرض وبيع المنتجات مع إدارة مخزون ذكية وتقارير مبيعات مفصلة", "icon": "storefront"}, {"title": "العلامات التجارية", "description": "متاجر تعكس هوية العلامة التجارية مع تجربة تسوق فريدة وبرامج ولاء متقدمة", "icon": "branding_watermark"}, {"title": "الأسواق الإلكترونية", "description": "منصات متعددة البائعين بنظام عمولات مرن وإدارة مركزية للطلبات والمدفوعات", "icon": "shopping_bag"}, {"title": "قطاع الأغذية والمطاعم", "description": "منصات طلب أونلاين مع إدارة قوائم الطعام وتكامل مع تطبيقات التوصيل", "icon": "restaurant"}]',
  '[{"title": "تجربة تسوق محسّنة للتحويل", "description": "تصميم رحلة شراء مدروسة تقلل خطوات الدفع وتزيد معدلات التحويل، مع عربة تسوق ذكية وعروض مخصصة بناءً على سلوك المتسوق.", "icon": "conversion_path"}, {"title": "بوابات دفع سعودية متكاملة", "description": "دعم جميع وسائل الدفع المحلية والعالمية بما فيها مدى و SADAD و Apple Pay والتقسيط عبر Tamara و Tabby مع تسوية مالية تلقائية.", "icon": "credit_card"}, {"title": "إدارة مخزون ذكية", "description": "نظام إدارة مخزون متقدم مع تنبيهات إعادة الطلب التلقائية وتتبع المنتجات عبر مستودعات متعددة ومزامنة فورية مع نقاط البيع.", "icon": "inventory_2"}, {"title": "تكامل شركات الشحن", "description": "ربط تلقائي مع شركات الشحن المحلية والدولية مع حساب تكلفة الشحن الآلي وتتبع الشحنات وإشعارات العملاء في الوقت الفعلي.", "icon": "local_shipping"}, {"title": "تحليلات وتقارير متقدمة", "description": "لوحة تحكم شاملة تعرض مؤشرات الأداء والمبيعات وسلوك العملاء مع تقارير مفصلة تساعد في اتخاذ قرارات تسويقية مبنية على البيانات.", "icon": "analytics"}, {"title": "متوافق مع الأنظمة السعودية", "description": "توافق كامل مع نظام التجارة الإلكترونية ومتطلبات ضريبة القيمة المضافة وحماية المستهلك والفوترة الإلكترونية ZATCA.", "icon": "gavel"}]',
  '["Shopify", "WooCommerce", "Magento", "Laravel", "Next.js", "Stripe", "HyperPay", "Moyasar", "Elasticsearch", "Redis", "AWS CloudFront", "Google Analytics"]',
  '[{"title": "تحليل السوق والمتطلبات", "description": "ندرس السوق المستهدف والمنافسين ونحدد الميزات الأساسية للمتجر مع اختيار المنصة التقنية الأنسب بناءً على حجم المنتجات وتوقعات النمو."}, {"title": "تصميم تجربة التسوق", "description": "نصمم واجهات المتجر وصفحات المنتجات ورحلة الشراء بأسلوب يركز على تحسين معدلات التحويل مع اختبارات A/B للتحقق من فعالية التصميم."}, {"title": "التطوير والتكامل", "description": "نبني المتجر ونربطه مع بوابات الدفع وشركات الشحن ونظام الفوترة الإلكترونية، مع إعداد نظام إدارة المنتجات والمخزون والطلبات."}, {"title": "الإطلاق والتسويق", "description": "نطلق المتجر مع خطة تسويقية متكاملة تشمل SEO وحملات إعلانية ومتابعة الأداء وتحسين معدلات التحويل بشكل مستمر بعد الإطلاق."}]',
  '[{"question": "أي منصة تجارة إلكترونية تنصحون بها؟", "answer": "يعتمد الاختيار على احتياجاتك. Shopify مثالي للمتاجر الصغيرة والمتوسطة بفضل سهولة الاستخدام. WooCommerce خيار ممتاز لمن يريد مرونة كاملة. Magento للمتاجر الكبرى ذات الكتالوجات الضخمة. نساعدك في اختيار الأنسب بناءً على ميزانيتك وخطط النمو."}, {"question": "هل تدعمون التقسيط والدفع الآجل؟", "answer": "نعم، نتكامل مع منصات التقسيط الرائدة في المملكة مثل Tamara و Tabby و Postpay التي تتيح للعملاء الدفع على أقساط بدون فوائد، مما يزيد متوسط قيمة الطلب بنسبة تصل إلى ٤٥٪."}, {"question": "هل يمكنكم ترحيل متجري الحالي؟", "answer": "نعم، نقوم بترحيل المتاجر من أي منصة مع نقل جميع البيانات بما فيها المنتجات والعملاء وسجل الطلبات والمراجعات. نضمن عدم فقدان أي بيانات مع الحفاظ على ترتيب SEO الحالي."}, {"question": "هل تقدمون خدمات تصوير المنتجات؟", "answer": "نوفر خدمة تصوير احترافي للمنتجات بالتعاون مع شركاء متخصصين، تشمل تصوير المنتجات بخلفية بيضاء وتصوير نمط الحياة وتصوير ٣٦٠ درجة للمنتجات التي تحتاج عرضاً تفاعلياً."}]',
  'uploads/services/ecommerce-stores.jpg',
  1,
  4,
  1
);

-- Service 5: حلول الذكاء الاصطناعي
INSERT INTO services (
  title, slug, icon, description, overview_content, full_content,
  color_scheme, subservices, stats, target_businesses, benefits,
  tech_stack, workflow, faq, featured_image, grid_col_span, sort_order, is_active
) VALUES (
  'حلول الذكاء الاصطناعي',
  'hulul-aldhaka-alasinai',
  'precision_manufacturing',
  'دمج تقنيات AI المتقدمة لتحليل البيانات وأتمتة العمليات المؤسسية، مع تخصيص نماذج معالجة اللغة العربية لتحقيق نتائج دقيقة في السياق السعودي.',
  '<p>نقدم حلول ذكاء اصطناعي متطورة مصممة لتحويل بيانات مؤسستك إلى رؤى قابلة للتنفيذ وأتمتة العمليات المتكررة. نتخصص في بناء نماذج تعلم آلي مخصصة تعالج تحديات الأعمال الفعلية في السوق السعودي، مع تركيز خاص على معالجة اللغة العربية الطبيعية بلهجاتها المختلفة.</p>
<p>من روبوتات المحادثة الذكية التي تخدم العملاء باللغة العربية إلى أنظمة التنبؤ بالطلب وتحليل المشاعر ورؤية الحاسوب، نوظّف أحدث تقنيات الذكاء الاصطناعي لمنح مؤسستك ميزة تنافسية حقيقية. نماذجنا مدربة على بيانات عربية وسعودية لضمان دقة النتائج في السياق المحلي.</p>
<p>نؤمن بأن الذكاء الاصطناعي يجب أن يكون عملياً وقابلاً للقياس. لذلك نبدأ كل مشروع بتحديد مؤشرات أداء واضحة ونقيس العائد على الاستثمار في كل مرحلة، مع ضمان أن الحلول قابلة للتوسع وسهلة الدمج مع أنظمتك القائمة.</p>',
  NULL,
  'cyan',
  '["تحليل البيانات الضخمة", "الأتمتة الذكية", "معالجة اللغة العربية", "التنبؤ والتوصيات"]',
  '[{"label": "مشروع ذكاء اصطناعي", "value": "+٤٠"}, {"label": "دقة النماذج التنبؤية", "value": "٪٩٥"}, {"label": "توفير في التكاليف التشغيلية", "value": "٪٤٠"}, {"label": "نموذج عربي مدرّب", "value": "+٢٠"}]',
  '[{"title": "القطاع المالي والتأمين", "description": "نماذج كشف الاحتيال وتقييم المخاطر الائتمانية وأتمتة معالجة المطالبات بدقة عالية", "icon": "savings"}, {"title": "قطاع التجزئة", "description": "أنظمة توصية ذكية وتنبؤ بالطلب وتحليل سلوك العملاء لزيادة المبيعات والاحتفاظ", "icon": "shopping_basket"}, {"title": "القطاع الصحي", "description": "تحليل الصور الطبية والتنبؤ بالأمراض ومساعدة التشخيص السريري بتقنيات التعلم العميق", "icon": "biotech"}, {"title": "القطاع الحكومي", "description": "تحليل البيانات الضخمة واستخراج الرؤى لدعم صنع القرار وتحسين الخدمات العامة", "icon": "public"}]',
  '[{"title": "معالجة لغة عربية متقدمة", "description": "نماذج NLP مدربة على بيانات عربية وسعودية تفهم اللهجات المحلية وتحلل المشاعر والنوايا بدقة عالية تصل إلى ٩٥٪ في التصنيف.", "icon": "record_voice_over"}, {"title": "روبوتات محادثة ذكية", "description": "شات بوتات تتحدث العربية بطلاقة وتفهم السياق وتخدم العملاء على مدار الساعة مع القدرة على التعلم والتحسن من كل محادثة.", "icon": "smart_toy"}, {"title": "تحليلات تنبؤية دقيقة", "description": "نماذج تعلم آلي تتنبأ بالطلب والمبيعات وسلوك العملاء لتمكين التخطيط الاستباقي واتخاذ قرارات مبنية على بيانات مستقبلية.", "icon": "trending_up"}, {"title": "رؤية حاسوبية", "description": "حلول تحليل الصور والفيديو لأغراض مراقبة الجودة والتعرف على الوجوه وقراءة المستندات العربية آلياً بدقة متناهية.", "icon": "visibility"}, {"title": "أتمتة ذكية للعمليات", "description": "دمج الذكاء الاصطناعي مع أتمتة العمليات الروبوتية RPA لأتمتة المهام المعقدة التي تتطلب فهماً وتحليلاً وليس مجرد تكرار.", "icon": "precision_manufacturing"}, {"title": "خصوصية وأمان البيانات", "description": "حلول تضمن خصوصية البيانات وتتوافق مع نظام حماية البيانات الشخصية السعودي مع إمكانية التشغيل المحلي بالكامل.", "icon": "shield"}]',
  '["Python", "TensorFlow", "PyTorch", "Hugging Face", "OpenAI API", "LangChain", "scikit-learn", "Apache Spark", "Kubernetes", "MLflow", "FastAPI", "Pinecone"]',
  '[{"title": "اكتشاف الفرص وتحليل البيانات", "description": "نحلل بياناتك الحالية ونحدد الفرص التي يمكن للذكاء الاصطناعي أن يحقق فيها أكبر عائد. نضع مؤشرات أداء واضحة وخطة تنفيذ عملية مبنية على أولويات العمل."}, {"title": "بناء النموذج والتدريب", "description": "نجمع البيانات ونعالجها ونبني نماذج مخصصة ندرّبها ونختبرها بشكل مكثف. نستخدم تقنيات التعلم الآلي والتعلم العميق الأنسب لكل حالة استخدام."}, {"title": "الاختبار والتحسين", "description": "نختبر النموذج على بيانات حقيقية ونقيس دقته ونحسّنه تكرارياً حتى يحقق الأداء المطلوب. نتحقق من عدم التحيز ونضمن عدالة النتائج."}, {"title": "النشر والمراقبة", "description": "ننشر النموذج في بيئة الإنتاج وندمجه مع أنظمتك القائمة. نراقب أداءه باستمرار ونعيد تدريبه دورياً لضمان استمرار دقته مع تغيّر البيانات."}]',
  '[{"question": "هل يمكن تطبيق الذكاء الاصطناعي في شركتي الصغيرة؟", "answer": "نعم بالتأكيد. الذكاء الاصطناعي ليس حكراً على الشركات الكبرى. نقدم حلولاً مناسبة لكل حجم بدءاً من شات بوتات خدمة العملاء وأنظمة التوصية البسيطة وصولاً إلى أتمتة المهام اليومية، بتكاليف معقولة وعائد استثمار سريع."}, {"question": "هل تدعمون اللغة العربية في حلول الذكاء الاصطناعي؟", "answer": "هذا من أبرز تخصصاتنا. لدينا نماذج معالجة لغة طبيعية مدربة على بيانات عربية وسعودية تفهم اللهجة المحلية والمصطلحات التجارية السعودية، سواء في تحليل المشاعر أو التصنيف أو روبوتات المحادثة."}, {"question": "ما البيانات التي تحتاجونها لبناء نموذج؟", "answer": "يعتمد على نوع المشروع. بشكل عام نحتاج بيانات تاريخية ذات صلة بالمشكلة المراد حلها. في حال عدم توفر بيانات كافية، يمكننا استخدام تقنيات مثل Transfer Learning والنماذج المدربة مسبقاً لبدء العمل ببيانات أقل."}, {"question": "كيف أقيس عائد الاستثمار من حلول AI؟", "answer": "نحدد مع العميل مؤشرات أداء واضحة قبل البدء مثل تقليل وقت المعالجة أو زيادة دقة التنبؤات أو خفض التكاليف التشغيلية. نقدم تقارير دورية تقارن الأداء قبل وبعد تطبيق الحل مع حساب العائد المالي الفعلي."}]',
  'uploads/services/ai-solutions.jpg',
  2,
  5,
  1
);

-- Service 6: تكامل الأنظمة و APIs
INSERT INTO services (
  title, slug, icon, description, overview_content, full_content,
  color_scheme, subservices, stats, target_businesses, benefits,
  tech_stack, workflow, faq, featured_image, grid_col_span, sort_order, is_active
) VALUES (
  'تكامل الأنظمة و APIs',
  'takaml-alanzimat-wa-apis',
  'api',
  'ربط الأنظمة المختلفة وبناء واجهات برمجة التطبيقات لضمان تدفق البيانات بسلاسة عبر منظومتك التقنية.',
  '<p>نتخصص في ربط الأنظمة المتفرقة داخل المؤسسة وبناء طبقة تكامل موحدة تضمن تدفق البيانات بسلاسة وأمان بين جميع التطبيقات والمنصات. نصمم وننفذ واجهات برمجة تطبيقات REST و GraphQL عالية الأداء تتبع أفضل المعايير العالمية في التوثيق والأمان والموثوقية.</p>
<p>لدينا خبرة واسعة في التكامل مع الأنظمة الحكومية السعودية بما فيها أبشر ونفاذ ومقيم والمنصة اللوجستية وأنظمة ZATCA، بالإضافة إلى التكامل مع الأنظمة البنكية وبوابات الدفع ومنصات التجارة الإلكترونية وأنظمة ERP العالمية مثل SAP و Oracle.</p>
<p>نبني حلول تكامل قابلة للتوسع تتعامل مع ملايين الطلبات يومياً، مع أنظمة مراقبة وتنبيه متقدمة لضمان استمرارية الخدمة. كما نوفر بوابات API مركزية تسهّل على فرق التطوير الداخلية والشركاء الخارجيين استهلاك الخدمات بأمان وكفاءة.</p>',
  NULL,
  'gold',
  '["REST APIs", "تكامل الأنظمة الحكومية", "بوابات الدفع", "خدمات الطرف الثالث"]',
  '[{"label": "تكامل تم تنفيذه", "value": "+٢٠٠"}, {"label": "طلب API يومياً", "value": "+١٠م"}, {"label": "وقت التشغيل المستمر", "value": "٪٩٩.٩"}, {"label": "نظام حكومي تم الربط معه", "value": "+١٥"}]',
  '[{"title": "المؤسسات الحكومية", "description": "ربط الأنظمة الداخلية مع المنصات الحكومية وتوحيد قنوات تقديم الخدمات الرقمية للمواطنين", "icon": "account_balance"}, {"title": "البنوك والمؤسسات المالية", "description": "تكامل آمن مع أنظمة الدفع والتحويلات والخدمات البنكية المفتوحة Open Banking", "icon": "account_balance_wallet"}, {"title": "شركات الاتصالات", "description": "ربط أنظمة الفوترة والعملاء والشبكات في منظومة تقنية موحدة عالية الأداء", "icon": "cell_tower"}, {"title": "شركات التقنية", "description": "بناء طبقة API لمنتجاتهم الرقمية تمكّن الشركاء والمطورين من البناء عليها", "icon": "developer_mode"}]',
  '[{"title": "بنية Microservices مرنة", "description": "نصمم بنية خدمات مصغرة قابلة للتوسع بشكل مستقل، مما يتيح تحديث وتطوير كل خدمة على حدة دون التأثير على بقية النظام.", "icon": "view_module"}, {"title": "أمان متعدد الطبقات", "description": "تطبيق OAuth 2.0 و JWT و API Keys مع تحديد الصلاحيات بدقة وتشفير البيانات أثناء النقل والتخزين ومراقبة محاولات الوصول المشبوهة.", "icon": "security"}, {"title": "توثيق تفاعلي شامل", "description": "توثيق API تفاعلي بمعيار OpenAPI/Swagger يتيح للمطورين استكشاف واختبار الخدمات مباشرة مع أمثلة عملية لكل نقطة وصول.", "icon": "description"}, {"title": "مراقبة وتنبيهات ذكية", "description": "أنظمة مراقبة لحظية تتتبع أداء كل API وتُرسل تنبيهات فورية عند حدوث أي خلل أو تجاوز لعتبات الأداء المحددة.", "icon": "monitoring"}, {"title": "إدارة الإصدارات", "description": "نظام إدارة إصدارات يضمن التوافق الخلفي ويتيح تحديث الخدمات بسلاسة دون تعطيل الأنظمة المرتبطة أو إيقاف الخدمة.", "icon": "history"}, {"title": "معالجة غير متزامنة", "description": "دعم المعالجة غير المتزامنة عبر أنظمة صفوف الرسائل لضمان عدم فقدان أي طلب والتعامل مع الأحمال العالية بكفاءة.", "icon": "sync"}]',
  '["Node.js", "Python FastAPI", "Kong API Gateway", "Apache Kafka", "RabbitMQ", "gRPC", "GraphQL", "Docker", "Kubernetes", "Terraform", "Datadog", "Swagger"]',
  '[{"title": "تحليل المنظومة التقنية", "description": "ندرس جميع الأنظمة القائمة ونرسم خريطة التكامل المطلوبة مع تحديد نقاط الاختناق والمخاطر المحتملة ومتطلبات الأداء والأمان لكل نقطة ربط."}, {"title": "تصميم بنية التكامل", "description": "نصمم بنية التكامل ونحدد البروتوكولات وصيغ البيانات ونكتب مواصفات API التفصيلية مع تصميم سيناريوهات التعامل مع الأخطاء وإعادة المحاولة."}, {"title": "التطوير والاختبار", "description": "نبني طبقة التكامل مع اختبارات شاملة تشمل اختبارات الأداء والأمان والتحمل، ونتحقق من سلامة تدفق البيانات في جميع السيناريوهات الممكنة."}, {"title": "النشر والمراقبة", "description": "ننشر الحل في بيئة الإنتاج مع أنظمة مراقبة متقدمة ولوحات بيانات تفاعلية تعرض حالة جميع نقاط التكامل، مع دعم فني متواصل لضمان الاستقرار."}]',
  '[{"question": "ما الأنظمة الحكومية التي يمكنكم الربط معها؟", "answer": "لدينا خبرة في الربط مع معظم المنصات الحكومية السعودية بما فيها نفاذ للتحقق من الهوية، أبشر، مقيم، المنصة اللوجستية، منظومة ZATCA للفوترة الإلكترونية، ومنصات وزارة التجارة وغيرها."}, {"question": "كيف تضمنون أمان البيانات أثناء التكامل؟", "answer": "نطبق أعلى معايير الأمان بما فيها تشفير TLS 1.3 لجميع الاتصالات، مصادقة OAuth 2.0، توقيع رقمي للطلبات، تحديد معدل الطلبات، وسجل تدقيق شامل. كما نجري اختبارات اختراق دورية لضمان سلامة الحل."}, {"question": "هل يمكنكم بناء API لنظامنا القديم؟", "answer": "نعم، نبني طبقة API حديثة فوق الأنظمة القديمة Legacy باستخدام نمط API Gateway، مما يتيح للأنظمة الأخرى التواصل مع نظامكم القديم بواجهات حديثة دون الحاجة لإعادة بنائه."}, {"question": "كيف تتعاملون مع الأحمال العالية؟", "answer": "نصمم حلول التكامل لتتحمل الأحمال العالية باستخدام تقنيات مثل التخزين المؤقت وصفوف الرسائل وموازنة الأحمال والتوسع الأفقي التلقائي. أنظمتنا تتعامل مع ملايين الطلبات يومياً بزمن استجابة لا يتجاوز مئات الميلي ثوانٍ."}]',
  'uploads/services/system-integration.jpg',
  1,
  6,
  1
);

-- Service 7: التسويق الرقمي و SEO
INSERT INTO services (
  title, slug, icon, description, overview_content, full_content,
  color_scheme, subservices, stats, target_businesses, benefits,
  tech_stack, workflow, faq, featured_image, grid_col_span, sort_order, is_active
) VALUES (
  'التسويق الرقمي و SEO',
  'altaswiq-alraqmi-wa-seo',
  'search_insights',
  'إدارة الحملات الرقمية واستهداف الجمهور المحلي بأساليب مدروسة تعزز الحضور الرقمي وتزيد المبيعات.',
  '<p>نقدم خدمات تسويق رقمي شاملة مصممة لتعزيز حضور مؤسستك على الإنترنت وزيادة العملاء والمبيعات. نجمع بين الإبداع والتحليل البياني لبناء استراتيجيات تسويقية فعّالة تستهدف الجمهور السعودي بدقة عبر محركات البحث ومنصات التواصل الاجتماعي والبريد الإلكتروني.</p>
<p>نتخصص في تحسين محركات البحث SEO للمواقع العربية، مع فهم عميق لخوارزميات Google وسلوك البحث المحلي في المملكة. فريقنا يطبّق أحدث استراتيجيات SEO التقني وبناء المحتوى والروابط الخلفية لضمان تصدر موقعك نتائج البحث في الكلمات المفتاحية الأهم لنشاطك التجاري.</p>
<p>ندير حملات إعلانية مدفوعة على Google Ads و Meta و Snapchat و TikTok بميزانيات محسّنة تحقق أعلى عائد على الإنفاق الإعلاني. نقدم تقارير شفافة ومفصلة تُظهر أداء كل قناة ومؤشرات التحويل، مع تحسين مستمر مبني على البيانات لتحقيق أفضل النتائج.</p>',
  NULL,
  'cyan',
  '["تحسين محركات البحث", "إدارة الحملات", "التحليلات", "إدارة المحتوى"]',
  '[{"label": "حملة ناجحة تم إطلاقها", "value": "+٣٠٠"}, {"label": "زيادة في الزيارات العضوية", "value": "٪٥٠٠"}, {"label": "متوسط عائد الإنفاق الإعلاني", "value": "x٨"}, {"label": "كلمة مفتاحية في الصفحة الأولى", "value": "+٢٠٠٠"}]',
  '[{"title": "المتاجر الإلكترونية", "description": "استراتيجيات تسويقية متكاملة تزيد حركة المرور وتحسّن معدلات التحويل والمبيعات عبر الإنترنت", "icon": "shopping_cart"}, {"title": "الشركات الناشئة", "description": "بناء الوعي بالعلامة التجارية واكتساب العملاء الأوائل باستراتيجيات نمو سريعة ومحسّنة التكلفة", "icon": "rocket_launch"}, {"title": "القطاع العقاري", "description": "حملات استهداف دقيقة للمشترين المحتملين مع صفحات هبوط محسّنة لتوليد العملاء المحتملين", "icon": "real_estate_agent"}, {"title": "القطاع الطبي والصحي", "description": "تسويق المراكز الطبية والمستشفيات مع التزام بأخلاقيات الإعلان الصحي وأنظمة وزارة الصحة", "icon": "local_hospital"}]',
  '[{"title": "SEO عربي متخصص", "description": "تحسين محركات البحث بخبرة عميقة في المحتوى العربي وفهم سلوك البحث السعودي والكلمات المفتاحية المحلية لتصدر نتائج Google في مجالك.", "icon": "manage_search"}, {"title": "حملات مدفوعة محسّنة", "description": "إدارة حملات إعلانية على Google و Meta و Snapchat و TikTok بتحسين مستمر للميزانية والاستهداف لتحقيق أعلى عائد على كل ريال يُنفق.", "icon": "campaign"}, {"title": "تسويق بالمحتوى", "description": "إنتاج محتوى عربي عالي الجودة يجذب الجمهور المستهدف ويبني الثقة بعلامتك التجارية ويحسّن ترتيبك في محركات البحث بشكل مستدام.", "icon": "edit_note"}, {"title": "تحليلات وتقارير شفافة", "description": "تقارير أداء مفصلة وشفافة تُظهر نتائج كل قناة تسويقية مع تحليل معدلات التحويل والعائد على الاستثمار بشكل دقيق وقابل للقياس.", "icon": "insights"}, {"title": "إدارة وسائل التواصل", "description": "إدارة حسابات التواصل الاجتماعي بمحتوى إبداعي وجدولة ذكية وتفاعل مع الجمهور يبني مجتمعاً رقمياً نشطاً حول علامتك التجارية.", "icon": "share"}, {"title": "تحسين معدل التحويل CRO", "description": "تحليل سلوك المستخدمين على موقعك وتحسين صفحات الهبوط ورحلة العميل لزيادة نسبة تحويل الزوار إلى عملاء فعليين.", "icon": "conversion_path"}]',
  '["Google Analytics 4", "Google Search Console", "SEMrush", "Ahrefs", "Google Ads", "Meta Ads Manager", "Snapchat Ads", "TikTok Ads", "Mailchimp", "HubSpot", "Hotjar", "Google Tag Manager"]',
  '[{"title": "التدقيق والتحليل", "description": "نجري تدقيقاً شاملاً لحضورك الرقمي الحالي ونحلل المنافسين والسوق ونحدد الفرص والفجوات، مع وضع أهداف قابلة للقياس ومؤشرات أداء واضحة."}, {"title": "بناء الاستراتيجية", "description": "نبني استراتيجية تسويق رقمي متكاملة تحدد القنوات والرسائل والميزانيات والجداول الزمنية، مع خطة محتوى تفصيلية تتناسب مع جمهورك المستهدف."}, {"title": "التنفيذ والتحسين", "description": "ننفذ الحملات وننتج المحتوى ونحسّن الموقع لمحركات البحث مع مراقبة يومية للأداء وتعديلات مستمرة لتحسين النتائج."}, {"title": "التقارير والتطوير", "description": "نقدم تقارير شهرية مفصلة مع تحليل عميق للنتائج وتوصيات للتحسين، مع مراجعة دورية للاستراتيجية وتحديثها بناءً على البيانات والتغيرات في السوق."}]',
  '[{"question": "متى سأرى نتائج من SEO؟", "answer": "تحسين محركات البحث استثمار طويل الأمد. عادةً تبدأ النتائج الأولية بالظهور خلال ٣-٦ أشهر، مع تحسن مستمر بمرور الوقت. الحملات المدفوعة تعطي نتائج فورية ونستخدمها لتغطية الفترة حتى نضج استراتيجية SEO."}, {"question": "كم تكلفة التسويق الرقمي شهرياً؟", "answer": "نقدم باقات تبدأ من ٥,٠٠٠ ريال شهرياً للشركات الصغيرة وتصل إلى ٥٠,٠٠٠ ريال أو أكثر للشركات الكبرى. التكلفة تعتمد على القنوات المطلوبة وحجم المنافسة والأهداف المحددة. نقدم عرضاً مخصصاً بعد دراسة احتياجاتك."}, {"question": "هل تديرون حسابات التواصل الاجتماعي؟", "answer": "نعم، نقدم خدمة إدارة شاملة لحسابات التواصل الاجتماعي تشمل إعداد خطة المحتوى والتصميم والنشر والتفاعل مع الجمهور وإدارة الحملات الإعلانية وتقارير الأداء الشهرية."}, {"question": "هل تقدمون خدمات التسويق عبر البريد الإلكتروني؟", "answer": "نعم، نبني استراتيجيات بريد إلكتروني متقدمة تشمل تصميم القوالب وتقسيم القوائم والأتمتة والحملات الموسمية مع تحليل معدلات الفتح والنقر والتحويل لتحسين الأداء باستمرار."}]',
  'uploads/services/digital-marketing-seo.jpg',
  1,
  7,
  1
);

-- Service 8: الصيانة والدعم التقني
INSERT INTO services (
  title, slug, icon, description, overview_content, full_content,
  color_scheme, subservices, stats, target_businesses, benefits,
  tech_stack, workflow, faq, featured_image, grid_col_span, sort_order, is_active
) VALUES (
  'الصيانة والدعم التقني',
  'alssiyana-waldaem-alttiqni',
  'support_agent',
  'دعم فني متواصل ومراقبة أداء الأنظمة على مدار الساعة لضمان استمرارية الأعمال وأعلى مستويات الموثوقية.',
  '<p>نوفر خدمات صيانة ودعم تقني شاملة تضمن استمرارية عمل أنظمتك الرقمية بأعلى كفاءة على مدار الساعة. فريقنا المتخصص يراقب أنظمتك بشكل استباقي ويكتشف المشكلات قبل أن تؤثر على سير العمل، مع استجابة فورية لأي طارئ تقني لتقليل وقت التوقف إلى أدنى حد.</p>
<p>نقدم باقات صيانة مرنة تشمل التحديثات الأمنية الدورية والنسخ الاحتياطي التلقائي ومراقبة الأداء وتحسينه وإصلاح الأخطاء وتحديث المحتوى. سواء كان لديك موقع إلكتروني أو تطبيق جوال أو نظام ERP أو بنية تحتية سحابية، نغطي جميع احتياجات الصيانة والدعم.</p>
<p>نؤمن بأن الصيانة الاستباقية أفضل وأوفر من الصيانة التفاعلية. لذلك نستخدم أدوات مراقبة متقدمة تتنبأ بالمشكلات المحتملة وتُنبّه فريقنا قبل حدوثها، مع تقارير أداء شهرية تفصيلية توضح حالة أنظمتك والإجراءات المتخذة والتوصيات المستقبلية.</p>',
  NULL,
